 29→const normalizeInteractionFlag = (value) => {
 30→    if(typeof value === 'boolean') return value;
 31→    if(typeof value === 'string'){
 32→        const normalized = value.trim().toLowerCase();
 33→        if(normalized === 'true') return true;
 34→        if(normalized === 'false') return false;
 35→    }
 36→    if(typeof value === 'number'){
 37→        return value === 1;
 38→    }
 39→    return Boolean(value);
 40→};
 41→
 42→const normalizeCount = (value) => {
 43→    const number = Number(value);
 44→    if(!Number.isFinite(number) || number < 0){
 45→        return 0;
 46→    }
 47→    return number;
 48→};
 49→
 50→const getNextToggleCount = (isActive, currentCount) => {
 51→    return isActive
 52→        ? Math.max(0, currentCount - 1)
 53→        : currentCount + 1;
 54→};
