104→    });
105→
106→    const postData = useMemo(() => {
107→        const journal = fetchedJournalData?.journal;
108→        if(journal){
109→            const postType = journal?.post_type || 'text';
110→            const parsedContent = ParseContent(journal?.content);
111→            const canvasDoc = postType === 'canvas' ? parseCanvasDoc(journal?.canvas_doc) : null;
112→            const wholeText = postType === 'canvas'
113→                ? getCanvasWholeText(canvasDoc)
114→                : (parsedContent?.wholeText || '');
115→
116→            return {
117→                postType: postType,
118→                content: journal?.content,
119→                canvasDoc: canvasDoc,
120→                wholeText: wholeText,
121→                title: journal?.title,
122→                userId: journal?.users?.id || journal?.user_id,
123→                name: journal?.users?.name,
124→                avatar: journal?.users?.image_url,
125→                created_at: journal?.created_at,
126→                journalId: journal?.id,
127→                isLiked: journal?.has_liked,
128→                commentsCount: journal?.comment_count?.[0]?.count || 0,
129→                isBookmarked: journal?.has_bookmarked,
130→                likesCount: journal?.like_count?.[0]?.count || 0,
131→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
132→                badge: journal?.users?.badge,
133→                isRepost: journal?.is_repost === true,
134→                repostCaption: journal?.repost_caption || '',
135→                repostSource: journal?.repost_source || null
136→            };
137→        }
138→
139→        if(!statePostData){
140→            return null;
141→        }
142→
143→        const inferredPostType = statePostData?.postType || (statePostData?.canvasDoc ? 'canvas' : 'text');
144→        const parsedContent = ParseContent(statePostData?.content);
145→        const canvasDoc = inferredPostType === 'canvas' ? parseCanvasDoc(statePostData?.canvasDoc) : null;
146→
147→        return {
148→            postType: inferredPostType,
149→            content: statePostData?.content,
150→            canvasDoc: canvasDoc,
151→            wholeText: inferredPostType === 'canvas'
152→                ? (statePostData?.wholeText || getCanvasWholeText(canvasDoc))
153→                : (statePostData?.wholeText || parsedContent?.wholeText || ''),
154→            title: statePostData?.title,
155→            userId: statePostData?.userId,
156→            name: statePostData?.name,
157→            avatar: statePostData?.avatar,
158→            created_at: statePostData?.created_at,
159→            journalId: statePostData?.journalId,
160→            isLiked: statePostData?.isLiked,
161→            commentsCount: statePostData?.commentsCount || 0,
162→            isBookmarked: statePostData?.isBookmarked,
163→            likesCount: statePostData?.likesCount || 0,
164→            bookmarksCount: statePostData?.bookmarksCount || 0,
165→            badge: statePostData?.badge,
166→            isRepost: statePostData?.isRepost === true,
167→            repostCaption: statePostData?.repostCaption || '',
168→            repostSource: statePostData?.repostSource || null
169→        };
170→    }, [fetchedJournalData, statePostData]);
171→
172→    const { data: followsData, isLoading: isLoadingFollows } = useQuery({
173→        queryKey: ['followsData', user?.userData?.[0]?.id, postData?.userId],
174→        queryFn: ({ queryKey }) => getFollowsData(queryKey[1], queryKey[2]),
175→        staleTime: 1000 * 60 * 60,
176→        cacheTime: 1000 * 60 * 60,
177→        enabled: !!user?.userData?.[0]?.id && !!postData?.userId,
178→    });
179→
180→    const handleclickUserProfile = handleClickProfile(navigate);
181→    const viewContent = handleCLickContent(navigate);
182→
183→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
184→    const handleClickLike = async (e, journalId, receiverId, senderImageUrl, sendername, senderEmail) => {
185→        e.stopPropagation();
186→        if(likeInFlightRef.current){
187→            return;
188→        }
189→        if(!session){
190→            openAuthModal?.();
191→            return;
192→        }
193→        const wasLiked = normalizeInteractionFlag(isLiked);
194→        likeInFlightRef.current = true;
195→        setIsliked(!wasLiked);
196→        setLikesCount((prevCount) => getNextToggleCount(wasLiked, normalizeCount(prevCount)));
197→        mutationLike.mutate(
198→            { journalId, receiverId, senderImageUrl, sendername, senderEmail },
199→            {
200→                onSettled: () => {
201→                    likeInFlightRef.current = false;
202→                }
203→            }
204→        );
205→    }
206→
207→    const mutationBookmark = useBookMarkMutation(session, user?.userData?.[0]?.id);
208→    const handleClickBookmark = async (e, journalId) => {
209→        e.stopPropagation();
210→        if(bookmarkInFlightRef.current){
211→            return;
212→        }
213→        if(!session){
214→            openAuthModal?.();
215→            return;
216→        }
217→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
218→        bookmarkInFlightRef.current = true;
219→        setIsBookmarked(!wasBookmarked);
220→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
221→        let response = null;
222→        try {
223→            response = await mutationBookmark.mutateAsync({ journalId });
224→        } finally {
225→            bookmarkInFlightRef.current = false;
226→        }
227→        
228→        if(timeOutRefBookmark.current){
229→            clearTimeout(timeOutRefBookmark.current);
230→        }
231→        if (response?.message === 'success') {
232→            setBookmarkedMessage('Post was added to your Bookmarks'); 
233→        } else if(response?.message === 'deleted'){
234→            setBookmarkedMessage('Post was removed from your Bookmarks');
235→        }
236→            
237→        timeOutRefBookmark.current = setTimeout(() => {
238→            setBookmarkedMessage('');
239→        }, 1500);
240→
241→    }
242→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
243→
244→    const mutationFollow = useFollowMutation(session);
245→    const handleClickFollow = async (e, followingId, followerId) => {
246→        e.stopPropagation();
247→        mutationFollow.mutate({ followingId, followerId });
248→    }
249→    const debounceClickFollow = debounce(handleClickFollow, 100);
250→
251→    const handleBackLocation = (e) => {
252→        e.stopPropagation();
253→        window.history.back();
254→    }
255→
256→    const hanldeClickComments = (e) => {
257→        e.stopPropagation();
258→        setShowCommentsContainer(true);
259→    }
260→
261→    const handleRemixCanvas = (e) => {
262→        e.stopPropagation();
263→        if(!session){
264→            return;
265→        }
266→
267→        const sourceTitle = typeof postData?.title === 'string' ? postData.title.trim() : '';
268→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
269→            ? sourceTitle
270→            : `Remix: ${sourceTitle || 'Canvas'}`;
271→
272→        navigate('/home', {
273→            state: {
274→                openEditor: true,
275→                editorMode: 'canvas',
276→                initialTitle: remixTitle,
277→                initialCanvasDoc: postData?.canvasDoc || null,
278→                remixSource: {
279→                    journalId: postData?.journalId,
280→                    authorName: postData?.name || 'Unknown'
281→                }
282→            }
283→        });
284→    }
285→
286→    const handleCLoseComments = () => {
287→        setShowCommentsContainer(false);
288→    }
289→
290→    useEffect(() => {
291→        if (!postData) return;
292→        setLikesCount(normalizeCount(postData?.likesCount));
