            try {
                fetchNextPage()
            } catch (error) {
                throw new Error(error);
            }
        }
    }

    useEffect(() =>{
        let timeout;
        if(textAreaFocusRef.current){
            timeout = setTimeout(() => {
                textAreaFocusRef.current.focus();
            }, 500);
        }
        return () => {
             clearTimeout(timeout);
        }
    }, [])

    const handeCloseCommentsSection = (e) =>{
        e.stopPropagation();
        onclose()
    }

